// Extract YouTube video ID from URL and pass through record_id
const input = $input.first().json;
const url = input.youtube_url || '';

// Support all YouTube URL formats
const patterns = [
  /[?&]v=([a-zA-Z0-9_-]{11})/,
  /youtu\.be\/([a-zA-Z0-9_-]{11})/,
  /embed\/([a-zA-Z0-9_-]{11})/,
  /shorts\/([a-zA-Z0-9_-]{11})/
];

let video_id = null;
for (const pattern of patterns) {
  const match = url.match(pattern);
  if (match) {
    video_id = match[1];
    break;
  }
}

if (!video_id) {
  throw new Error('Could not extract YouTube video ID from URL: ' + url);
}

return [{
  json: {
    record_id: input.record_id,
    youtube_url: url,
    video_id
  }
}];

// Parse YouTube timedtext JSON3 format and extract plain text
// Preserves record_id and video_id from previous node
const prev = $('Extract Video ID').first().json;
const response = $input.first().json;

let transcript = '';
let has_content = false;

try {
  // Timedtext JSON3 format: { events: [{ segs: [{ utf8: '...' }] }] }
  if (response.events && Array.isArray(response.events) && response.events.length > 0) {
    const parts = [];
    for (const event of response.events) {
      if (event.segs && Array.isArray(event.segs)) {
        for (const seg of event.segs) {
          if (seg.utf8 && seg.utf8.trim()) {
            parts.push(seg.utf8);
          }
        }
      }
    }
    const raw = parts.join('');
    // Clean up whitespace and newlines
    transcript = raw.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
    has_content = transcript.length > 50;
  }
} catch (e) {
  // Parse error — has_content stays false, falls through to fallback
}

return [{
  json: {
    record_id: prev.record_id,
    youtube_url: prev.youtube_url,
    video_id: prev.video_id,
    transcript,
    has_content,
    method: 'timedtext_asr'
  }
}];

// Parse manual captions (same format as ASR, without kind=asr)
const prev = $('Parse Timedtext ASR').first().json;
const response = $input.first().json;

let transcript = '';
let has_content = false;

try {
  if (response.events && Array.isArray(response.events) && response.events.length > 0) {
    const parts = [];
    for (const event of response.events) {
      if (event.segs && Array.isArray(event.segs)) {
        for (const seg of event.segs) {
          if (seg.utf8 && seg.utf8.trim()) {
            parts.push(seg.utf8);
          }
        }
      }
    }
    const raw = parts.join('');
    transcript = raw.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
    has_content = transcript.length > 50;
  }
} catch (e) {
  // Parse error
}

return [{
  json: {
    record_id: prev.record_id,
    youtube_url: prev.youtube_url,
    video_id: prev.video_id,
    transcript,
    has_content,
    method: 'timedtext_manual'
  }
}];

// PHASE 2 STUB: Whisper + Deepgram fallback
// This path runs when timedtext (both ASR and manual) returns no content.
//
// Phase 2 prerequisites needed before implementing:
// 1. Cloudflare Worker URL for yt-dlp audio extraction
//    - Deploy to Michael's existing Cloudflare account
//    - Worker accepts YouTube URL, returns audio stream/URL
// 2. OpenAI API credential added to n8n (separate from OpenRouter)
//    - For videos < 25MB: use native n8n OpenAI Whisper node
// 3. Deepgram API key added to n8n credentials
//    - For audio files > 25MB: Deepgram accepts hosted audio URLs directly
//
// Once Phase 2 prerequisites are in place, this stub should be replaced with:
//   HTTP Request → Cloudflare Worker (get audio URL)
//   → Check file size
//   → If < 25MB: OpenAI Whisper node
//   → If >= 25MB: Deepgram HTTP Request

const prev = $input.first().json;

return [{
  json: {
    record_id: prev.record_id,
    transcript: '',
    method: 'none',
    success: false,
    error: 'PHASE_2_STUB: Timedtext unavailable for this video. Whisper/Deepgram fallback requires Cloudflare Worker + credentials (see Phase 2).'
  }
}];
